function y = f(x)
    y = x + 1;
endfunction

rand("seed", 0)
x1 = floor(rand(5,1)*5)-1.5;
x2 = -floor(rand(5,1)*5)+0.5;
t = table(x1, x2, "VariableNames", ["x1", "x2"])

v = varfun(f, t)

// with sum 
v = varfun(sum, t)

// With timeseries
timestamp = hours([1 2 2 3 3])';
ts = timeseries(timestamp, x1, x2, "VariableNames", ["timestamp", "x1", "x2"])

v = varfun(f, ts)

// with sum 
v = varfun(sum, ts)

function y = f(x)
    y = x + 1;
endfunction

rand("seed", 0)
x1 = floor(rand(5,1)*5)-1.5;
x2 = -floor(rand(5,1)*5)+0.5;
t = table(x1, x2, "VariableNames", ["x1", "x2"])

v = varfun(f, t, "InputVariables", "x2")

// with sum 
v = varfun(sum, t, "InputVariables", "x1")

// Possible with extraction: t(:, ["var1", ..., "varN"])
v = varfun(f, t(:, "x2"))

v = varfun(sum, t(:, "x1"))

// With timeseries
timestamp = hours([1 2 2 3 3])';
ts = timeseries(timestamp, x1, x2, "VariableNames", ["timestamp", "x1", "x2"])

v = varfun(f, ts, "InputVariables", "x2")

// with sum 
v = varfun(sum, ts, "InputVariables", "x1")

// Possible with extraction: ts(:, ["var1", ..., "varN"])
v = varfun(f, ts(:, "x2"))

v = varfun(sum, ts(:, "x1"))

timestamp = hours([0.352500; 0.352700; 0.352900; 0.353100; 0.353300; 0.353500; 0.353700; 0.353900]);
x1 = [1:8]';
x2 = ["Rx"; "Rx"; "Rx"; "Rx"; "Rx"; "Rx"; "Rx"; "Rx"];
msg = ["A   0   0   0"; "A A   0   0   0"; "A A A  0   0   0"; "A A A A   0   0   0"; "A A A A A   0   0   0"; ...
"A A A A A A  0   0   0"; "A A A A A A A  0   0   0"; "A A A A A A A A  0   0   0"];
ts = timeseries(timestamp, x1, x2, msg, "VariableNames", ["timestamp", "x1", "x2", "message"]);

f = #(x) -> (strsubst(x, " ", ""));
v = varfun(f, ts, "InputVariables", "message");

function y = f(x)
    y = x' * x;
endfunction

rand("seed", 0)
x = ["a"; "b"; "b"; "c"; "a"];
x1 = floor(rand(5,1)*5)-1.5;
x2 = -floor(rand(5,1)*5)+0.5;
t = table(x, x1, x2, "VariableNames", ["x", "x1", "x2"])

v = varfun(f, t, "GroupingVariables", "x")

// with sum 
v = varfun(sum, t, "GroupingVariables", "x", "InputVariables", "x1")

// With timeseries
timestamp = hours([1 2 2 3 3])';
ts = timeseries(timestamp, x1, x2, "VariableNames", ["timestamp", "x1", "x2"])

v = varfun(f, ts, "GroupingVariables", "timestamp")

// with sum 
v = varfun(sum, ts, "GroupingVariables", "timestamp", "InputVariables", "x1")
